B.abZ=new A.dj(B.e5,"R Median Palmar   | 1.8 ms   | 80 uV | 8 cm  | 44 m/s | (<2.2, >50, >50)")
B.abP=new A.dj(B.dA,"F-WAVE STUDIES:")
