B.HW=new A.f3("Duration","Time from the initial to final baseline crossing. This reflects the number of muscle fibers firing synchronously in the motor unit.")
B.HR=new A.f3("Amplitude","Peak-to-peak voltage measurement. Keep in mind, this is heavily dependent on how close your needle tip is to the firing fibers.")
B.HX=new A.f3("Phases","Baseline crossings plus one. A critical measure of synchrony.")
B.HO=new A.f3("Initial Deflection","Is it positive (down) or negative (up)? Up is normal (endplate spikes) down means active denervation.")
B.HU=new A.f3("Shape","Are you seeing a brief spike (fibrillation) or a slow positive wave (PSW)?")
B.a2m=s([B.HW,B.HR,B.HX,B.HO,B.HU],t.PZ)
B.HY=new A.mF("Morphology",B.a2m)
B.HK=new A.f3("Stable","The morphology remains completely consistent from firing to firing.")
B.HV=new A.f3("Waxing/Waning","Amplitude changes smoothly over time. Think 'dive bomber' \u2013 classic myotonia.")
B.HQ=new A.f3("Decrementing","A progressive, steady decrease in amplitude.")
B.HL=new A.f3("Abrupt Changes","Discrete jumps in morphology, often suggesting unstable neuromuscular transmission.")
B.HM=new A.f3("Blocking","Intermittent failure of a muscle fiber to fire. You'll see the wave occasionally drop an entire phase.")
B.a1z=s([B.HK,B.HV,B.HQ,B.HL,B.HM],t.PZ)
B.I_=new A.mF("Stability",B.a1z)
B.HS=new A.f3("Rate","Ranges from very slow (<2Hz, like fasciculations) to extremely fast (>100Hz, like myotonia).")
B.HT=new A.f3("Pattern","Is it perfectly regular (CRDs), irregular (fibrillations), or bursting (myokymia)?")
B.HP=new A.f3("Rhythm","Distinguish between a semi-rhythmic 'rain on a tin roof' vs. perfectly regular 'machine-like' firing.")
B.HN=new A.f3("Recruitment","Observe how units activate with increasing force. Does the rate go up, or do more units jump in?")
B.HJ=new A.f3("Voluntary Control","Remember this pearl: Nobody has voluntary control under 4-5Hz. If it's firing at 2Hz, it's spontaneous.")
B.Z0=s([B.HS,B.HT,B.HP,B.HN,B.HJ],t.PZ)
B.HZ=new A.mF("Firing Characteristics",B.Z0)
