b8=A.cf(A.a([A.db(!0,p2,"Baseline","1.5mV","Pre-Exercise Median CMAP",f0),A.db(!0,"220% Increase","Facilitation","4.8mV","Post-10s Exercise Median CMAP",f0)],m),b9,b8)
b5=A.cd(aa8,b7,s2,"INDICATED (Look for facilitation)",A.a([A.z(!1,f0,f0,f0,f0,f0,g9,h0,f0,f0,h1,f0),A.z(!0,f0,f0,f0,f0,"Small/Short (Myopathic appearance due to RNS deficit)",m7,m8,f0,s1,m9,f0),A.z(!0,f0,f0,f0,f0,"Small/Short",n0,m8,f0,s1,aa5,f0)],n),"LEMS is a pre-synaptic NMJ disorder caused by antibodies against P/Q-type voltage-gated calcium channels (VGCC). It is characterized by proximal weakness, autonomic dysfunction (dry mouth), and diminished reflexes that paradoxically improve after brief exercise (reflex potentiation). Electrodiagnosis confirms low baseline CMAP amplitudes that markedly facilitate (>100%) after 10 seconds of max exercise or high-frequency RNS.",b6,"lems",b8,ae7,ae6,!0,b5,A.a(["LEMS is a pre-synaptic disorder characterized by low baseline CMAP amplitudes.","Facilitation (>100% increase in CMAP amplitude) after 10 seconds of exercise is diagnostic.","Approximately 50-60% of LEMS cases are associated with an underlying malignancy, most commonly Small Cell Lung Cancer (SCLC).","Clinical Pearl: Reflex potentiation (reflexes returning after exercise) is a classic finding."],af2),"Weakness Improving with Exercise")
ae6=A.cc(52,"6-month history of progressive difficulty walking and weakness in both hands",i1,"52-year-old male with gradual onset of weakness in his legs, starting 6 months ago. He now has difficulty climbing stairs and rising from a chair. Over the last 3 months, he noticed weakness in his hands and difficulty with fine motor tasks like buttoning shirts. Numbness and tingling in feet and hands. No preceding illness. Symptoms have been steadily progressive without plateau.",i4,"Accountant",i3)
ae7=A.cg("Normal muscle bulk in the shoulders and thighs. Mild atrophy of the hand intrinsic muscles. Gait is wide-based and slightly steady.",ab9,"Absent (0) Achilles, Patellar, Biceps, and Triceps reflexes bilaterally.",v3,"Symmetric decreased light touch, pinprick, and vibration in a stocking-glove distribution (up to knees and wrists). Marked reduction in proprioception at toes.","Positive Romberg test. Negative Babinski.","Proximal weakness: Hip flexion 4/5, Shoulder abduction 4/5. Distal weakness: Dorsiflexion 4/5, Grip strength 3+/5, Finger abduction 3/5.")
b8=A.a([A.V(ab5,d9),A.V("Guillain-Barr\xe9 Syndrome (GBS)","GBS is acute (peak <4 weeks); this patient has been progressing for 6 months."),A.V(ac0,"Diabetes typically causes an axonal (amplitude loss) length-dependent neuropathy; CIDP shows striking demyelinating features (slowing, block) and significant proximal involvement."),A.V(ab3,"MMN is purely motor (no sensory loss) and is typically asymmetric."),A.V("POEMS Syndrome","Can mimic CIDP, but would usually have associated systemic findings (organomegaly, endocrinopathy, M-protein, skin changes).")],ae8)
b6=A.a4(["constitutional","No fever, no recent weight loss.","musculoskeletal","Weakness in all four limbs, worse proximally. No joint pain.","neurological","Progressive weakness and numbness. Significant balance issues. No bowel/bladder changes."],af0,af0)
