c2=A.a([A.V(ac8,d9),A.V(ac9,"S1 radiculopathy would typically cause an absent Achilles reflex and denervation in proximal S1 muscles (Gastrocnemius, Gluteus Maximus); here both are normal."),A.V(ac7,"Primarily a pain syndrome at the calcaneal insertion; would not cause the significant intrinsic muscle denervation and plantar NCS abnormalities seen here."),A.V(ac0,"Usually presents with symmetric 'stocking-glove' distribution and abnormal Sural SNAPs; here findings are focal and the Sural is normal."),A.V(p8,"Sciatic lesions would involve the peroneal division (TA, EHL) and the Sural SNAP; here those are entirely spared.")],ae8)
