c5=A.cd(x8,c7,d4,ae0,A.a([A.z(!1,"Spared (rules out femoral/plexus/L3 root)",f0,f0,f0,f0,m7,m8,f0,f0,m9,f0),A.z(!1,"Spared (rules out L2-L3 roots)",f0,f0,f0,f0,n0,m8,f0,f0,aa5,f0),A.z(!1,z0,f0,f0,f0,f0,t6,t7,f0,f0,m9,f0),A.z(!1,h7,f0,f0,f0,f0,l5,l6,f0,f0,l7,f0),A.z(!1,h7,f0,f0,f0,f0,m0,l6,f0,f0,m1,f0),A.z(!1,h7,f0,f0,f0,f0,m2,q7,f0,f0,m1,f0),A.z(!1,h7,f0,f0,f0,f0,m4,m5,f0,f0,m6,f0),A.z(!1,f0,f0,f0,f0,f0,"Lumbar Paraspinals (L2-L4)",f0,f0,f0,f0,k6)],n),"Compression of the Lateral Femoral Cutaneous Nerve (LFCN) under the inguinal ligament. This is a purely sensory nerve; therefore, there should be NO weakness on exam. EMG is used to confirm the absence of motor involvement (ruling out radiculopathy) while NCS may show a delayed or absent LFCN SNAP.",c6,"meralgia",c8,ae7,ae6,!0,c5,A.a(["Meralgia paresthetica is a compression of the LFCN as it passes under the inguinal ligament near the ASIS.","Common risk factors include obesity, pregnancy, and wearing tight clothing or heavy belts.","Localization Pearl: It is a purely sensory nerve. The presence of ANY motor weakness immediately rules out isolated meralgia paresthetica.","NCS can be technically difficult to obtain, especially in obese patients, making clinical correlation paramount."],af2),"The Burning Thigh")
ae6=A.cc(38,"Pain and numbness on the top of the right foot, especially when wearing tight cleats.",i1,"Professional soccer player who noticed aching pain in the dorsal ankle and numbness in the first webspace (between big toe and second toe) after wearing new, tight cleats. Pain is worse with ankle dorsiflexion and at night. No leg weakness. No back pain.",i4,"Soccer Player","History of ankle sprains")
ae7=A.cg("Atrophy of the Extensor Digitorum Brevis (EDB) muscle belly on the lateral top of the foot.","Tenderness over the anterior ankle, just deep to the extensor retinaculum. No tenderness at the fibular head.",ad8,"Full ROM of the ankle and toes.","Decreased sensation strictly localized to the first dorsal webspace. Normal sensation on the lateral and medial foot.","Positive Tinel's sign over the deep peroneal nerve at the anterior ankle (extensor retinaculum).","5/5 Strength in Tibialis Anterior, EHL, and Peroneals. Unable to specifically test EDB strength effectively, but atrophy is noted.")
c8=A.a([A.V(ae2,d9),A.V("Common Peroneal Neuropathy (Fibular Head)","A lesion at the fibular head would cause weakness in the TA and EHL (foot drop) and sensory loss across the entire dorsal foot; here, TA/EHL are normal and sensory loss is restricted to the first webspace."),A.V(p7,"Radiculopathy would cause weakness in TA/EHL and hip abductors, and would usually spare the EDB amplitude on NCS (pre-ganglionic). This case is strictly distal."),A.V("First Webspace Neuroma","Would cause localized digital pain but would NOT cause EDB atrophy or an abnormal EDB motor study."),A.V("Sural Neuropathy","Involves the lateral foot sensation; this case is first webspace (Deep Peroneal territory).")],ae8)
c6=A.a4(["constitutional","Negative.","musculoskeletal","Dorsal foot pain.","neurological","First webspace numbness. No Foot Drop."],af0,af0)
c7=A.a(["None."],af2)
c7=A.ce(A.a(["Ultrasound Ankle: Flattening of the deep peroneal nerve beneath the extensor retinaculum; associated with a small ganglion cyst."],af2),c7)
c9=A.a([A.ad(!1,q2,h7,k5,g6,i7),A.ad(!1,q1,h7,k7,i6,f9),A.ad(!0,"2.0","Confirms isolated first webspace involvement","Deep Peroneal Sensory",g4,e9)],q)
